class NullIngredient {
  constructor(name, ingredient, ctx) {
    this._ingredient = ingredient;
    this._ctx = ctx;
  }

  async Execute() {
    const params = this._ingredient?.properties?.parameters;
    if (!params || typeof params.entries !== 'function') {
      return;
    }

    for (const [, variable] of params.entries()) {
      if (variable && typeof variable.valueAsync === 'function') {
        await variable.valueAsync(this._ctx);
      }
    }
  }
}

module.exports = {
  pluginNS: '@azbake/ingredient-null',
  plugin: NullIngredient
};